{
  "name": "Quirky - Social IQ Builder",
  "description": "A next-gen social skills companion designed to boost your Social and Emotional Quotient (SEQ). Practice real-world scenarios with an AI friend, receive instant confidence analytics, and future-proof your communication skills through interactive roleplay and behavioral insights."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export interface Scenario {
  id: string;
  title: string;
  description: string;
  difficulty: 'Easy' | 'Medium' | 'Hard';
  category: 'Professional' | 'Social' | 'Romance' | 'Conflict';
  initialPrompt: string;
  aiPersona: string;
}

export interface AnalysisResult {
  confidenceScore: number;
  empathyScore: number;
  feedback: string;
  betterAlternative?: string;
}

export enum View {
  DASHBOARD = 'DASHBOARD',
  CHAT = 'CHAT',
  LEARN = 'LEARN',
  PROFILE = 'PROFILE'
}

export interface UserStats {
  streak: number;
  conversations: number;
  avgConfidence: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Message, AnalysisResult } from '../types';

// Initialize the client. 
// NOTE: In a real production app, ensure process.env.API_KEY is defined.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateChatResponse = async (
  history: Message[], 
  userMessage: string,
  persona: string
): Promise<string> => {
  try {
    const model = 'gemini-3-flash-preview';

    // Construct conversation history for context
    const chatHistory = history.map(msg => ({
      role: msg.role === 'model' ? 'model' : 'user',
      parts: [{ text: msg.text }]
    }));

    const chat = ai.chats.create({
      model: model,
      history: chatHistory,
      config: {
        systemInstruction: `You are a roleplay partner in a social skills training app. 
        Your Persona: ${persona}.
        Goal: Engage the user in a realistic conversation. 
        Keep responses concise (under 3 sentences) unless the topic demands depth.
        React naturally to the user's tone. If they are rude, react accordingly. If they are shy, encourage them gently or dominate conversation depending on your persona.`,
      }
    });

    const result = await chat.sendMessage({ message: userMessage });
    return result.text || "I'm listening...";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "I'm having a bit of trouble connecting to my social brain right now. Can we try that again?";
  }
};

export const analyzeConversation = async (lastUserMessage: string): Promise<AnalysisResult> => {
  try {
    const model = 'gemini-3-flash-preview';

    const prompt = `Analyze the following social statement for confidence and empathy. Return JSON.
    Statement: "${lastUserMessage}"

    JSON Schema:
    {
      confidenceScore: number (0-100),
      empathyScore: number (0-100),
      feedback: string (short tip, max 15 words),
      betterAlternative: string (optional, how to say it better)
    }`;

    const result = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            confidenceScore: { type: Type.NUMBER },
            empathyScore: { type: Type.NUMBER },
            feedback: { type: Type.STRING },
            betterAlternative: { type: Type.STRING }
          }
        }
      }
    });

    const text = result.text;
    if (!text) throw new Error("No data returned");

    return JSON.parse(text) as AnalysisResult;
  } catch (error) {
    console.error("Analysis Error:", error);
    return {
      confidenceScore: 50,
      empathyScore: 50,
      feedback: "Keep practicing!",
      betterAlternative: "Try to be more direct."
    };
  }
};

export const generateDailyTip = async (): Promise<string> => {
   try {
    const result = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: "Give me a one-sentence quirky, insightful tip about social psychology or body language for Gen Z.",
    });
    return result.text || "Smile! It's the universal language.";
   } catch (e) {
     return "Eye contact shows confidence, but don't stare!";
   }
}

