import React from 'react';
import { Scenario } from '../types';
import { MessageCircle, Zap, Shield, Heart } from 'lucide-react';

interface ScenarioCardProps {
  scenario: Scenario;
  onClick: (scenario: Scenario) => void;
}

export const ScenarioCard: React.FC<ScenarioCardProps> = ({ scenario, onClick }) => {
  const getIcon = () => {
    switch (scenario.category) {
      case 'Professional': return <Shield className="w-5 h-5 text-blue-500" />;
      case 'Romance': return <Heart className="w-5 h-5 text-pink-500" />;
      case 'Conflict': return <Zap className="w-5 h-5 text-yellow-500" />;
      default: return <MessageCircle className="w-5 h-5 text-green-500" />;
    }
  };

  const getDifficultyColor = () => {
    switch (scenario.difficulty) {
      case 'Easy': return 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300';
      case 'Medium': return 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-300';
      case 'Hard': return 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-300';
    }
  };

  return (
    <div 
      onClick={() => onClick(scenario)}
      className="group bg-white dark:bg-dark-card border border-gray-100 dark:border-gray-700 p-5 rounded-2xl shadow-sm hover:shadow-xl hover:scale-[1.02] transition-all duration-300 cursor-pointer flex flex-col justify-between"
    >
      <div>
        <div className="flex justify-between items-start mb-3">
          <div className="p-2 bg-gray-50 dark:bg-gray-800 rounded-full group-hover:bg-primary-50 dark:group-hover:bg-gray-700 transition-colors">
            {getIcon()}
          </div>
          <span className={`text-xs font-semibold px-2.5 py-0.5 rounded-full ${getDifficultyColor()}`}>
            {scenario.difficulty}
          </span>
        </div>
        <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-1 group-hover:text-primary-600 dark:group-hover:text-primary-400 transition-colors">
          {scenario.title}
        </h3>
        <p className="text-sm text-gray-500 dark:text-gray-400">
          {scenario.description}
        </p>
      </div>
      <div className="mt-4 flex items-center text-xs font-medium text-gray-400 dark:text-gray-500">
        AI Persona: <span className="text-gray-600 dark:text-gray-300 ml-1">{scenario.aiPersona}</span>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  MessageSquare, 
  Home, 
  BookOpen, 
  User, 
  Send, 
  Moon, 
  Sun, 
  Sparkles, 
  Mic, 
  Volume2,
  RefreshCw,
  ArrowLeft
} from 'lucide-react';
import { Logo } from './components/Logo';
import { ScenarioCard } from './components/ScenarioCard';
import { generateChatResponse, analyzeConversation, generateDailyTip } from './services/geminiService';
import { Message, Scenario, View, AnalysisResult } from './types';

// --- Constants & Data ---
const SCENARIOS: Scenario[] = [
  {
    id: '1',
    title: 'Networking Event Intro',
    description: 'Break the ice with a stranger at a professional mixer.',
    difficulty: 'Easy',
    category: 'Professional',
    initialPrompt: "Hi there! I don't think we've met yet, I'm...",
    aiPersona: 'A friendly but busy industry professional named Alex.'
  },
  {
    id: '2',
    title: 'Asking for a Raise',
    description: 'Negotiate a salary increase with your manager.',
    difficulty: 'Hard',
    category: 'Conflict',
    initialPrompt: "Hi, do you have a moment to talk about my performance?",
    aiPersona: 'A skeptical manager named Sarah who focuses on data and results.'
  },
  {
    id: '3',
    title: 'First Date Small Talk',
    description: 'Keep the conversation flowing on a coffee date.',
    difficulty: 'Medium',
    category: 'Romance',
    initialPrompt: "So, what do you like to do on weekends?",
    aiPersona: 'A slightly shy but interested date named Jordan.'
  },
  {
    id: '4',
    title: 'Disagreeing Politely',
    description: 'Express a differing opinion without being rude.',
    difficulty: 'Hard',
    category: 'Social',
    initialPrompt: "I actually see it a bit differently...",
    aiPersona: 'A passionate friend named Casey who loves debates.'
  }
];

// --- Main App Component ---
function App() {
  // State
  const [darkMode, setDarkMode] = useState(false);
  const [currentView, setCurrentView] = useState<View>(View.DASHBOARD);
  const [activeScenario, setActiveScenario] = useState<Scenario | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [dailyTip, setDailyTip] = useState("Loading your daily social cue...");
  const [lastAnalysis, setLastAnalysis] = useState<AnalysisResult | null>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Effects
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  useEffect(() => {
    // Load daily tip on mount
    generateDailyTip().then(setDailyTip);
  }, []);

  useEffect(() => {
    // Scroll to bottom of chat
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Handlers
  const handleScenarioSelect = (scenario: Scenario) => {
    setActiveScenario(scenario);
    setMessages([{
      id: '0',
      role: 'model',
      text: `(Scenario: ${scenario.title}) Hi! I'm ${scenario.aiPersona.split(' ')[0]}. ${scenario.description} Ready when you are!`,
      timestamp: Date.now()
    }]);
    setCurrentView(View.CHAT);
  };

  const handleSendMessage = async () => {
    if (!inputText.trim() || !activeScenario) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsLoading(true);
    setLastAnalysis(null); // Clear previous analysis

    try {
        // Parallel execution: Get response AND analyze user confidence
        const [response, analysis] = await Promise.all([
            generateChatResponse([...messages, userMsg], userMsg.text, activeScenario.aiPersona),
            analyzeConversation(userMsg.text)
        ]);

        const aiMsg: Message = {
            id: (Date.now() + 1).toString(),
            role: 'model',
            text: response,
            timestamp: Date.now()
        };

        setMessages(prev => [...prev, aiMsg]);
        setLastAnalysis(analysis);

    } catch (error) {
        console.error(error);
    } finally {
        setIsLoading(false);
    }
  };

  const toggleTheme = () => setDarkMode(!darkMode);

  // --- Sub-Components (Render Functions) ---

  const renderDashboard = () => (
    <div className="space-y-8 animate-fade-in">
      <header className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white">
            Hello, <span className="bg-gradient-to-r from-primary-500 to-purple-500 bg-clip-text text-transparent">Socialite</span>
          </h1>
          <p className="text-gray-500 dark:text-gray-400 mt-1">Ready to level up your EQ today?</p>
        </div>
        <button className="p-2 bg-white dark:bg-dark-card rounded-full shadow-sm border border-gray-100 dark:border-gray-700 animate-float">
          <Sparkles className="w-6 h-6 text-yellow-500" />
        </button>
      </header>

      {/* Daily Tip Card */}
      <div className="relative overflow-hidden bg-gradient-to-r from-violet-600 to-indigo-600 rounded-2xl p-6 text-white shadow-lg">
        <div className="absolute top-0 right-0 -mt-4 -mr-4 w-24 h-24 bg-white/10 rounded-full blur-2xl"></div>
        <h2 className="text-lg font-semibold mb-2 flex items-center gap-2">
          <Sparkles className="w-4 h-4" /> Daily Social Insight
        </h2>
        <p className="text-xl font-medium leading-relaxed opacity-90">"{dailyTip}"</p>
      </div>

      {/* Scenarios Grid */}
      <div>
        <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-4">Pick a Scenario</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {SCENARIOS.map(scenario => (
            <ScenarioCard 
              key={scenario.id} 
              scenario={scenario} 
              onClick={handleScenarioSelect} 
            />
          ))}
        </div>
      </div>

       {/* Quick Stats */}
      <div className="grid grid-cols-2 gap-4">
         <div className="bg-white dark:bg-dark-card p-4 rounded-2xl border border-gray-100 dark:border-gray-700 shadow-sm">
            <div className="text-3xl font-bold text-primary-600 mb-1">3</div>
            <div className="text-xs text-gray-500 dark:text-gray-400 font-medium uppercase tracking-wider">Day Streak</div>
         </div>
         <div className="bg-white dark:bg-dark-card p-4 rounded-2xl border border-gray-100 dark:border-gray-700 shadow-sm">
            <div className="text-3xl font-bold text-purple-600 mb-1">84%</div>
            <div className="text-xs text-gray-500 dark:text-gray-400 font-medium uppercase tracking-wider">Avg Confidence</div>
         </div>
      </div>
    </div>
  );

  const renderChat = () => (
    <div className="flex flex-col h-[calc(100vh-120px)] md:h-[calc(100vh-80px)]">
      <div className="flex items-center gap-4 mb-4 pb-4 border-b border-gray-100 dark:border-gray-800">
        <button 
          onClick={() => setCurrentView(View.DASHBOARD)}
          className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full transition-colors"
        >
          <ArrowLeft className="w-5 h-5 text-gray-600 dark:text-gray-300" />
        </button>
        <div>
          <h2 className="font-bold text-gray-900 dark:text-white">{activeScenario?.title}</h2>
          <p className="text-xs text-green-500 flex items-center gap-1">
            <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
            Online
          </p>
        </div>
      </div>

      {/* Chat Area */}
      <div className="flex-1 overflow-y-auto space-y-4 pr-2 mb-4">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div 
              className={`max-w-[80%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-primary-600 text-white rounded-br-none' 
                  : 'bg-white dark:bg-gray-800 text-gray-800 dark:text-gray-200 rounded-bl-none border border-gray-100 dark:border-gray-700'
              }`}
            >
              {msg.text}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white dark:bg-gray-800 p-4 rounded-2xl rounded-bl-none border border-gray-100 dark:border-gray-700 flex gap-2">
              <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></span>
              <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-100"></span>
              <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-200"></span>
            </div>
          </div>
        )}
        <div ref={chatEndRef} />
      </div>

      {/* Real-time Insight Toast */}
      {lastAnalysis && !isLoading && (
         <div className="mb-4 bg-gradient-to-r from-gray-900 to-gray-800 dark:from-gray-800 dark:to-gray-700 text-white p-3 rounded-xl text-xs flex items-center justify-between shadow-lg animate-slide-up">
            <div className="flex items-center gap-3">
               <div className={`p-1.5 rounded-full ${lastAnalysis.confidenceScore > 70 ? 'bg-green-500' : 'bg-yellow-500'}`}>
                  <Sparkles className="w-3 h-3 text-white" />
               </div>
               <div>
                 <p className="font-bold">Insight: {lastAnalysis.feedback}</p>
                 {lastAnalysis.betterAlternative && (
                   <p className="opacity-70 mt-0.5 italic">Try: "{lastAnalysis.betterAlternative}"</p>
                 )}
               </div>
            </div>
            <div className="text-right pl-4 border-l border-white/20">
               <div className="font-bold">{lastAnalysis.confidenceScore}%</div>
               <div className="text-[10px] opacity-70">Confidence</div>
            </div>
         </div>
      )}

      {/* Input Area */}
      <div className="relative">
        <input
          type="text"
          value={inputText}
          onChange={(e) => setInputText(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
          placeholder="Type your response..."
          disabled={isLoading}
          className="w-full bg-gray-100 dark:bg-gray-800 text-gray-900 dark:text-white rounded-full pl-6 pr-14 py-4 focus:outline-none focus:ring-2 focus:ring-primary-500 transition-all shadow-inner"
        />
        <button 
          onClick={handleSendMessage}
          disabled={isLoading || !inputText.trim()}
          className="absolute right-2 top-2 p-2 bg-primary-600 hover:bg-primary-700 text-white rounded-full transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
          <Send className="w-5 h-5" />
        </button>
      </div>
    </div>
  );

  return (
    <div className={`flex h-screen w-full bg-gray-50 dark:bg-dark-bg transition-colors duration-300 overflow-hidden`}>
      {/* Sidebar / Mobile Nav */}
      <nav className="fixed bottom-0 md:static md:w-64 w-full h-16 md:h-full bg-white dark:bg-dark-card border-t md:border-r border-gray-200 dark:border-gray-800 z-50 flex md:flex-col justify-between p-4 md:p-6 shadow-2xl md:shadow-none">

        {/* Logo Area */}
        <div className="hidden md:flex items-center gap-3 mb-10">
          <Logo size={48} />
          <span className="font-bold text-2xl tracking-tight text-gray-900 dark:text-white">Quirky</span>
        </div>

        {/* Navigation Items */}
        <div className="flex md:flex-col justify-around w-full gap-2 md:gap-4">
          {[
            { id: View.DASHBOARD, icon: Home, label: 'Home' },
            { id: View.CHAT, icon: MessageSquare, label: 'Practice' },
            { id: View.LEARN, icon: BookOpen, label: 'Learn' },
            { id: View.PROFILE, icon: User, label: 'Profile' },
          ].map((item) => (
            <button
              key={item.id}
              onClick={() => setCurrentView(item.id)}
              className={`flex items-center gap-3 p-3 rounded-xl transition-all duration-200 ${
                currentView === item.id
                  ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 font-semibold'
                  : 'text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800'
              }`}
            >
              <item.icon className="w-6 h-6 md:w-5 md:h-5" />
              <span className="hidden md:block text-sm">{item.label}</span>
            </button>
          ))}
        </div>

        {/* Theme Toggle (Desktop Footer) */}
        <div className="hidden md:block mt-auto pt-6 border-t border-gray-100 dark:border-gray-700">
          <button 
            onClick={toggleTheme}
            className="flex items-center gap-3 w-full p-3 text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-xl transition-all"
          >
            {darkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            <span className="text-sm font-medium">{darkMode ? 'Light Mode' : 'Dark Mode'}</span>
          </button>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 overflow-hidden relative">
        {/* Mobile Header */}
        <div className="md:hidden flex justify-between items-center p-4 bg-white/80 dark:bg-dark-card/80 backdrop-blur-md sticky top-0 z-40 border-b border-gray-100 dark:border-gray-800">
           <div className="flex items-center gap-2">
             <Logo size={32} />
             <span className="font-bold text-lg text-gray-900 dark:text-white">Quirky</span>
           </div>
           <button onClick={toggleTheme} className="p-2 rounded-full bg-gray-100 dark:bg-gray-800">
              {darkMode ? <Sun className="w-4 h-4" /> : <Moon className="w-4 h-4" />}
           </button>
        </div>

        <div className="h-full overflow-y-auto p-4 md:p-10 pb-24 md:pb-10 max-w-5xl mx-auto">
          {currentView === View.DASHBOARD && renderDashboard()}
          {currentView === View.CHAT && renderChat()}
          {currentView === View.LEARN && (
            <div className="flex flex-col items-center justify-center h-full text-center space-y-4">
              <div className="bg-primary-100 dark:bg-primary-900/30 p-6 rounded-full">
                <BookOpen className="w-12 h-12 text-primary-600 dark:text-primary-400" />
              </div>
              <h2 className="text-2xl font-bold text-gray-900 dark:text-white">Knowledge Vault</h2>
              <p className="text-gray-500 max-w-md">Curated psychology lessons and body language video guides coming soon to help you master the theory before the practice.</p>
            </div>
          )}
          {currentView === View.PROFILE && (
             <div className="flex flex-col items-center justify-center h-full text-center space-y-4">
              <div className="w-24 h-24 bg-gradient-to-tr from-primary-400 to-purple-500 rounded-full p-1">
