import { GoogleGenAI, Type } from "@google/genai";
import { Message, AnalysisResult } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const MODEL_NAME = 'gemini-3-flash-preview';

export const generateChatResponse = async (
  history: Message[], 
  userMessage: string,
  persona: string,
  category: string
): Promise<string> => {
  try {
    const chatHistory = history.map(msg => ({
      role: msg.role === 'model' ? 'model' : 'user',
      parts: [{ text: msg.text }]
    }));

    let systemInstruction = `You are a roleplay partner in 'Socibuild', a social skills app. 
        Your Persona: ${persona}.
        Goal: Engage the user in a realistic conversation.`;

    if (category === 'Interview') {
      systemInstruction += " You are a strict but fair interviewer. Ask probing questions. Evaluate their answers implicitly by your follow-up questions.";
    } else if (category === 'Listening') {
      systemInstruction += " You are telling a story or giving instructions. Periodically ask the user to recall details to test their listening. Be talkative.";
    } else {
      systemInstruction += " Keep responses concise (under 3 sentences) unless the topic demands depth. React naturally to the user's tone.";
    }

    const chat = ai.chats.create({
      model: MODEL_NAME,
      history: chatHistory,
      config: { systemInstruction }
    });

    const result = await chat.sendMessage({ message: userMessage });
    return result.text || "I'm listening...";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Connection glitch. Let's try that again.";
  }
};

export const analyzeConversation = async (lastUserMessage: string): Promise<AnalysisResult> => {
  try {
    const prompt = `Analyze this social statement. Return JSON.
    Statement: "${lastUserMessage}"

    JSON Schema:
    {
      confidenceScore: number (0-100),
      empathyScore: number (0-100),
      feedback: string (max 15 words),
      betterAlternative: string (optional)
    }`;

    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            confidenceScore: { type: Type.NUMBER },
            empathyScore: { type: Type.NUMBER },
            feedback: { type: Type.STRING },
            betterAlternative: { type: Type.STRING }
          }
        }
      }
    });

    const text = result.text;
    if (!text) throw new Error("No data returned");
    return JSON.parse(text) as AnalysisResult;
  } catch (error) {
    return { confidenceScore: 50, empathyScore: 50, feedback: "Keep practicing!", betterAlternative: "Try to be more direct." };
  }
};

export const generateDailyTip = async (): Promise<string> => {
   try {
    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: "Give me a one-sentence insightful tip about social psychology, charisma, or body language.",
    });
    return result.text || "Smile! It's the universal language.";
   } catch (e) {
     return "Active listening is the secret to charisma.";
   }
}

export const refineEmail = async (draft: string, tone: 'Professional' | 'Casual' | 'Assertive'): Promise<string> => {
  try {
    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Rewrite the following email draft to be ${tone}, concise, and effective.

      Draft: "${draft}"`,
    });
    return result.text || draft;
  } catch (e) {
    return "Error refining text.";
  }
}

export const analyzeBehaviorDescription = async (description: string): Promise<string> => {
  try {
    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Analyze the behavior described below. Explain the potential underlying emotions, social cues missed, or intentions based on psychology. Be helpful and empathetic.

      Description: "${description}"`,
    });
    return result.text || "I couldn't analyze that behavior.";
  } catch (e) {
    return "Analysis failed.";
  }
}

