    if (userMode === 'Work') return ['Professional', 'Conflict', 'Interview'].includes(s.category);
    return ['Social', 'Romance', 'Listening'].includes(s.category);
  });

  const handleScenarioSelect = (scenario: Scenario) => {
    setActiveScenario(scenario);
    setMessages([{
      id: '0',
      role: 'model',
      text: `(Scenario: ${scenario.title}) Hi! I'm ${scenario.aiPersona.split(' ')[0]}. ${scenario.description}`,
      timestamp: Date.now()
    }]);
    setCurrentView(View.CHAT);
    setMobileMenuOpen(false);
  };

  const handleSendMessage = async () => {
    if (!inputText.trim() || !activeScenario) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: inputText, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsLoading(true);
    setLastAnalysis(null);

    try {
        const [response, analysis] = await Promise.all([
            generateChatResponse([...messages, userMsg], userMsg.text, activeScenario.aiPersona, activeScenario.category, userProfile),
            analyzeConversation(userMsg.text)
        ]);

        setMessages(prev => [...prev, { id: (Date.now() + 1).toString(), role: 'model', text: response, timestamp: Date.now() }]);
        setLastAnalysis(analysis);
    } catch (error) {
        console.error(error);
    } finally {
        setIsLoading(false);
    }
  };

  const handleToolSubmit = async () => {
    if (!toolInput.trim()) return;
    setIsLoading(true);
    let result = '';
    if (activeTool === 'Email') {
      result = await refineEmail(toolInput, userMode === 'Work' ? 'Professional' : 'Casual');
    } else if (activeTool === 'Behavior') {
      result = await analyzeBehaviorDescription(toolInput);
    }
    setToolOutput(result);
    setIsLoading(false);
  };

