import { GoogleGenAI, Type } from "@google/genai";
import { Message, AnalysisResult, UserProfile } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const MODEL_NAME = 'gemini-3-flash-preview';

export const generateChatResponse = async (
  history: Message[], 
  userMessage: string,
  persona: string,
  category: string,
  userProfile?: UserProfile
): Promise<string> => {
  try {
    const chatHistory = history.map(msg => ({
      role: msg.role === 'model' ? 'model' : 'user',
      parts: [{ text: msg.text }]
    }));

    let systemInstruction = `You are a roleplay partner in 'Socibuild'. 
        Your Persona: ${persona}.
        User Profile: ${userProfile ? `Age: ${userProfile.age}, Gender: ${userProfile.gender}, Job: ${userProfile.occupation}` : 'Unknown'}.
        Goal: Engage the user in a realistic conversation suited to their demographics.`;

    if (category === 'Interview') {
      systemInstruction += " You are a strict interviewer. Ask probing questions relevant to their occupation if known.";
    } else if (category === 'Listening') {
      systemInstruction += " You are telling a story. Periodically ask the user to recall details.";
    } else {
      systemInstruction += " Keep responses concise. React naturally.";
    }

    const chat = ai.chats.create({
      model: MODEL_NAME,
      history: chatHistory,
      config: { systemInstruction }
    });

    const result = await chat.sendMessage({ message: userMessage });
    return result.text || "I'm listening...";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Connection glitch. Let's try that again.";
  }
};

export const analyzeConversation = async (lastUserMessage: string): Promise<AnalysisResult> => {
  try {
    const prompt = `Analyze this social statement. Return JSON.
    Statement: "${lastUserMessage}"

    JSON Schema:
    {
      confidenceScore: number (0-100),
      empathyScore: number (0-100),
      feedback: string (max 15 words),
      betterAlternative: string (optional)
    }`;

    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            confidenceScore: { type: Type.NUMBER },
            empathyScore: { type: Type.NUMBER },
            feedback: { type: Type.STRING },
            betterAlternative: { type: Type.STRING }
          }
        }
      }
    });

    const text = result.text;
    if (!text) throw new Error("No data returned");
    return JSON.parse(text) as AnalysisResult;
  } catch (error) {
    return { confidenceScore: 50, empathyScore: 50, feedback: "Keep practicing!", betterAlternative: "Try to be more direct." };
  }
};

export const generateDailyTip = async (userProfile?: UserProfile): Promise<string> => {
   try {
    const prompt = userProfile 
      ? `Give me a one-sentence social tip for a ${userProfile.age} year old ${userProfile.gender} working in ${userProfile.occupation}.` 
      : "Give me a one-sentence insightful tip about social psychology.";

    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
    });
    return result.text || "Smile! It's the universal language.";
   } catch (e) {
     return "Active listening is the secret to charisma.";
   }
}

export const analyzeEmailDraft = async (draft: string, tone: string): Promise<{critique: string, rewrite: string}> => {
  try {
    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Analyze and rewrite this email/letter draft. 
      Target Tone: ${tone}.

      Return JSON with:
      - 'critique': Specific feedback on clarity, tone, and professionalism (max 30 words).
      - 'rewrite': The polished version of the text.

      Draft: "${draft}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            critique: { type: Type.STRING },
            rewrite: { type: Type.STRING }
          }
        }
      }
    });
    const text = result.text;
    if (!text) return { critique: "Analysis failed.", rewrite: draft };
    return JSON.parse(text);
  } catch (e) {
    return { critique: "Could not analyze text.", rewrite: "Error processing request." };
  }
}

export const analyzeBehaviorDescription = async (description: string): Promise<string> => {
  try {
    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Analyze the behavior described below. Explain the potential underlying emotions, social cues missed, or intentions based on psychology. Description: "${description}"`,
    });
    return result.text || "I couldn't analyze that behavior.";
  } catch (e) {
    return "Analysis failed.";
  }
}

export const generateLessonContent = async (lessonTitle: string, userProfile?: UserProfile): Promise<string> => {
  try {
    const context = userProfile 
      ? `Target Audience: ${userProfile.age} year old ${userProfile.gender}, ${userProfile.occupation}.` 
      : "Target Audience: General Learner.";

    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Write a short, engaging educational lesson (approx 150 words) about "${lessonTitle}". 
      ${context}
      Include a practical "Try This" exercise at the end. 
      Format with Markdown.`,
    });
    return result.text || "Content currently unavailable.";
  } catch (e) {
    return "Could not load lesson content.";
  }
}

export const generateQuizQuestion = async (lessonTitle: string): Promise<{question: string, options: string[], correctIndex: number}> => {
  try {
    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Create one multiple choice question based on the topic "${lessonTitle}". Return JSON.
      Schema: { question: string, options: string[], correctIndex: number }`,
      config: {
        responseMimeType: "application/json",
         responseSchema: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            correctIndex: { type: Type.NUMBER }
          }
        }
      }
    });
    const text = result.text;
    if(!text) throw new Error("No quiz data");
    return JSON.parse(text);
  } catch (e) {
    return { question: "What represents confidence?", options: ["Slouching", "Eye Contact", "Mumbling"], correctIndex: 1 };
  }
}

