    name: 'Guest',
    age: '25',
    gender: 'Prefer not to say',
    occupation: 'Student',
    goals: 'Improve confidence'
  });
  const [activeCourse, setActiveCourse] = useState<Course | null>(null);
  const [activeLesson, setActiveLesson] = useState<Lesson | null>(null);
  const [lessonContent, setLessonContent] = useState('');
  const [quizData, setQuizData] = useState<{question: string, options: string[], correctIndex: number} | null>(null);

  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (darkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [darkMode]);

  useEffect(() => {
    generateDailyTip(userProfile).then(setDailyTip);
  }, [userProfile]); // Refresh tip when profile changes

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, activeCommunityChat]);

  const filteredScenarios = ALL_SCENARIOS.filter(s => {
    if (userMode === 'Work') return ['Professional', 'Conflict', 'Interview'].includes(s.category);
    return ['Social', 'Romance', 'Listening'].includes(s.category);
  });

  const handleScenarioSelect = (scenario: Scenario) => {
    setActiveScenario(scenario);
    setMessages([{
      id: '0',
      role: 'model',
      text: `(Scenario: ${scenario.title}) Hi! I'm ${scenario.aiPersona.split(' ')[0]}. ${scenario.description}`,
      timestamp: Date.now()
    }]);
    setCurrentView(View.CHAT);
    setMobileMenuOpen(false);
  };

  const handleSendMessage = async () => {
    if (!inputText.trim() || !activeScenario) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: inputText, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsLoading(true);
    setLastAnalysis(null);

    try {
        const [response, analysis] = await Promise.all([
            generateChatResponse([...messages, userMsg], userMsg.text, activeScenario.aiPersona, activeScenario.category, userProfile),
            analyzeConversation(userMsg.text)
        ]);

        setMessages(prev => [...prev, { id: (Date.now() + 1).toString(), role: 'model', text: response, timestamp: Date.now() }]);
        setLastAnalysis(analysis);
    } catch (error) {
        console.error(error);
    } finally {
        setIsLoading(false);
    }
  };

  const handleToolSubmit = async () => {
    if (!toolInput.trim()) return;
    setIsLoading(true);
    let result: any = '';
    if (activeTool === 'Email') {
      result = await analyzeEmailDraft(toolInput, emailTone);
    } else if (activeTool === 'Behavior') {
      result = await analyzeBehaviorDescription(toolInput);
    }
    setToolOutput(result);
    setIsLoading(false);
  };

  const handleStartLesson = async (lesson: Lesson) => {
    setActiveLesson(lesson);
    setLessonContent("Generating personalized lesson content...");
    setQuizData(null);
    const content = await generateLessonContent(lesson.title, userProfile);
