                        <div className="absolute bottom-20 left-4 right-4 md:left-auto md:right-10 md:w-80 bg-white/95 dark:bg-gray-800/95 backdrop-blur shadow-2xl border border-primary-100 dark:border-gray-700 p-4 rounded-xl text-xs animate-slide-up z-30">
                           <div className="flex justify-between items-start mb-2">
                               <h4 className="font-bold text-primary-600 uppercase tracking-wider">Coach Insight</h4>
                               <span className={`px-2 py-0.5 rounded text-white ${lastAnalysis.confidenceScore > 70 ? 'bg-green-500' : 'bg-yellow-500'}`}>{lastAnalysis.confidenceScore}% Conf.</span>
                           </div>
                           <p className="text-gray-700 dark:text-gray-300 mb-1">{lastAnalysis.feedback}</p>
                           {lastAnalysis.betterAlternative && <p className="text-gray-500 italic border-l-2 border-primary-200 pl-2 mt-2">Try: "{lastAnalysis.betterAlternative}"</p>}
                        </div>
                      )}
                      <div className="relative">
                        <input
                          type="text"
                          value={inputText}
                          onChange={(e) => setInputText(e.target.value)}
                          onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                          placeholder="Type your response..."
                          disabled={isLoading}
                          className="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 text-gray-900 dark:text-white rounded-xl pl-4 pr-14 py-4 focus:outline-none focus:ring-2 focus:ring-primary-500 transition-all shadow-sm"
                        />
                        <button onClick={handleSendMessage} disabled={isLoading || !inputText.trim()} className="absolute right-2 top-2 p-2 bg-primary-600 hover:bg-primary-700 text-white rounded-lg transition-colors">
                          <Send className="w-5 h-5" />
                        </button>
                      </div>
                    </div>
                )}
           </div>
        </div>
      </main>
    </div>
  );
}

export default App;

