export const generateQuizQuestion = async (lessonTitle: string): Promise<{question: string, options: string[], correctIndex: number}> => {
  try {
    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Create one multiple choice question based on the topic "${lessonTitle}". Return JSON.
      Schema: { question: string, options: string[], correctIndex: number }`,
      config: {
        responseMimeType: "application/json",
         responseSchema: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            correctIndex: { type: Type.NUMBER }
          }
        }
      }
    });
    const text = result.text;
    if(!text) throw new Error("No quiz data");
    return JSON.parse(text);
  } catch (e) {
    return { question: "What represents confidence?", options: ["Slouching", "Eye Contact", "Mumbling"], correctIndex: 1 };
  }
}

export const generateInterviewQuestions = async (role: string): Promise<string[]> => {
  try {
    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Generate 5 common and challenging interview questions for a ${role} position. Return them as a simple JSON array of strings.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });
    const text = result.text;
    if(!text) return ["Tell me about yourself.", "What are your weaknesses?"];
    return JSON.parse(text);
  } catch(e) {
    return ["Tell me about yourself.", "Why do you want this job?", "Describe a challenge you overcame."];
  }
}

export const evaluateInterviewAnswer = async (question: string, answer: string): Promise<InterviewFeedback> => {
  try {
    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Evaluate this interview answer.
      Question: "${question}"
      Answer: "${answer}"

      Return JSON:
      - score (0-10)
      - strengths (array of strings)
      - improvements (array of strings)
      - sampleAnswer (a better version of the answer)`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
           type: Type.OBJECT,
           properties: {
             score: { type: Type.NUMBER },
             strengths: { type: Type.ARRAY, items: { type: Type.STRING }},
             improvements: { type: Type.ARRAY, items: { type: Type.STRING }},
             sampleAnswer: { type: Type.STRING }
           }
        }
      }
    });
    const text = result.text;
    if(!text) throw new Error("No feedback generated");
    return JSON.parse(text);
  } catch(e) {
    return {
       score: 5,
       strengths: ["Attempted to answer"],
       improvements: ["Be more specific", "Use the STAR method"],
       sampleAnswer: "I demonstrated leadership by..."
    };
  }
}

