                        </button>
                        <div>
                          <h2 className="font-bold text-gray-900 dark:text-white">{activeScenario?.title}</h2>
                          <p className="text-xs text-primary-500 flex items-center gap-1">Speaking with: {activeScenario?.aiPersona}</p>
                        </div>
                      </div>
                      <div className="flex-1 overflow-y-auto space-y-4 pr-2 mb-4 scrollbar-hide">
                        {messages.map((msg) => (
                          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                            <div className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm ${msg.role === 'user' ? 'bg-primary-600 text-white rounded-br-none' : 'bg-white dark:bg-gray-800 text-gray-800 dark:text-gray-200 rounded-bl-none border border-gray-100 dark:border-gray-700'}`}>
                              {msg.text}
                            </div>
                          </div>
