export const generateInterviewQuestions = async (role: string): Promise<string[]> => {
  try {
    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Generate 5 common and challenging interview questions for a ${role} position. Return them as a simple JSON array of strings.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });
