export const evaluateInterviewAnswer = async (question: string, answer: string): Promise<InterviewFeedback> => {
  try {
    const result = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Evaluate this interview answer.
      Question: "${question}"
