           <div className="mb-4 flex items-center gap-2">
              <button onClick={() => { setActiveLesson(null); setQuizData(null); }} className="text-sm text-gray-500 hover:text-gray-900 flex items-center gap-1">
                 <ChevronRight className="w-4 h-4 rotate-180" /> Back to Course
              </button>
