                 <div>
                    <span className="text-xs font-bold text-primary-500 uppercase tracking-wider">{activeLesson.type}</span>
                    <h1 className="text-3xl font-bold text-gray-900 dark:text-white mt-2">{activeLesson.title}</h1>
                 </div>
                 <div className="bg-gray-100 dark:bg-gray-800 p-2 rounded-lg">
                    {activeLesson.type === 'Quiz' ? <HelpCircle className="w-6 h-6 text-gray-500" /> : <BookOpen className="w-6 h-6 text-gray-500" />}
                 </div>
               </div>

