// --- Main App Component ---
function App() {
  const [darkMode, setDarkMode] = useState(false);
  const [currentView, setCurrentView] = useState<View>(View.DASHBOARD);
  const [activeScenario, setActiveScenario] = useState<Scenario | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [dailyTip, setDailyTip] = useState("Loading insight...");
  const [lastAnalysis, setLastAnalysis] = useState<AnalysisResult | null>(null);
  const [userMode, setUserMode] = useState<'Personal' | 'Work'>('Personal');
  const [activeTool, setActiveTool] = useState<'Email' | 'Behavior' | 'Vibe' | null>(null);
  const [toolInput, setToolInput] = useState('');
  const [toolOutput, setToolOutput] = useState<any>('');
  const [emailTone, setEmailTone] = useState('Professional');
  const [communityUsers, setCommunityUsers] = useState<CommunityUser[]>(INITIAL_COMMUNITY_USERS);
  const [activeCommunityChat, setActiveCommunityChat] = useState<CommunityUser | null>(null);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [vibeImage, setVibeImage] = useState<string | null>(null);

  // New State for Learning & Profile
  const [userProfile, setUserProfile] = useState<UserProfile>({
    name: 'Guest',
    age: '25',
    gender: 'Prefer not to say',
    occupation: 'Student',
    goals: 'Improve confidence',
    interests: 'Technology, Art',
    learningStyle: 'Visual',
    socialAnxieties: 'Public Speaking'
  });
  const [activeCourse, setActiveCourse] = useState<Course | null>(null);
  const [activeLesson, setActiveLesson] = useState<Lesson | null>(null);
  const [lessonContent, setLessonContent] = useState('');
  const [quizData, setQuizData] = useState<{question: string, options: string[], correctIndex: number} | null>(null);
  const [socialIQ, setSocialIQ] = useState(115); // Default mock IQ

  // Interview Prep State
  const [interviewRoleInput, setInterviewRoleInput] = useState('');
  const [interviewQuestions, setInterviewQuestions] = useState<string[]>([]);
  const [activeInterviewQuestion, setActiveInterviewQuestion] = useState<string | null>(null);
  const [interviewAnswerInput, setInterviewAnswerInput] = useState('');
  const [interviewFeedback, setInterviewFeedback] = useState<InterviewFeedback | null>(null);

  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (darkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [darkMode]);

  useEffect(() => {
    generateDailyTip(userProfile).then(setDailyTip);
    // Initialize interview role from profile
    if (userProfile.occupation) setInterviewRoleInput(userProfile.occupation);
  }, [userProfile]); 

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, activeCommunityChat]);

  const filteredScenarios = ALL_SCENARIOS.filter(s => {
    if (userMode === 'Work') return ['Professional', 'Conflict', 'Interview'].includes(s.category);
    return ['Social', 'Romance', 'Listening'].includes(s.category);
  });

  const handleScenarioSelect = (scenario: Scenario) => {
    setActiveScenario(scenario);
    setMessages([{
      id: '0',
      role: 'model',
      text: `(Scenario: ${scenario.title}) Hi! I'm ${scenario.aiPersona.split(' ')[0]}. ${scenario.description} ${scenario.initialPrompt}`,
      timestamp: Date.now()
    }]);
    setLastAnalysis(null);
    setCurrentView(View.CHAT);
    setMobileMenuOpen(false);
  };

  const handleSendMessage = async () => {
    if (!inputText.trim() || !activeScenario) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: inputText, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsLoading(true);

    try {
        const [response, analysis] = await Promise.all([
            generateChatResponse([...messages, userMsg], userMsg.text, activeScenario.aiPersona, activeScenario.category, userProfile),
            analyzeConversation(userMsg.text)
        ]);

        setMessages(prev => [...prev, { id: (Date.now() + 1).toString(), role: 'model', text: response, timestamp: Date.now() }]);
        setLastAnalysis(analysis);
        // Slightly update IQ based on confidence (mock logic)
        if (analysis.confidenceScore > 80) setSocialIQ(prev => Math.min(160, prev + 1));
    } catch (error) {
        console.error(error);
    } finally {
        setIsLoading(false);
    }
  };

  const handleToolSubmit = async () => {
    setIsLoading(true);
    let result: any = '';

    if (activeTool === 'Email' && toolInput.trim()) {
      result = await analyzeEmailDraft(toolInput, emailTone);
    } else if (activeTool === 'Behavior' && toolInput.trim()) {
      result = await analyzeBehaviorDescription(toolInput);
    } else if (activeTool === 'Vibe' && vibeImage) {
      result = await analyzeImageVibe(vibeImage.split(',')[1]); // Send base64 without prefix
    }

    setToolOutput(result);
    setIsLoading(false);
  };

  const handleFindPartner = () => {
    setIsLoading(true);
    setTimeout(() => {
        const newFriend: CommunityUser = {
            id: `u${Date.now()}`,
            name: ['Alex M.', 'Jordan K.', 'Taylor R.'][Math.floor(Math.random() * 3)],
            status: 'online',
            avatar: `https://i.pravatar.cc/150?u=${Date.now()}`,
            bio: 'New here! Looking to practice.'
        };
        setCommunityUsers(prev => [...prev, newFriend]);
        setIsLoading(false);
        setActiveCommunityChat(newFriend);
    }, 1500);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const reader = new FileReader();
          reader.onloadend = () => {
              setVibeImage(reader.result as string);
              setToolOutput(null);
          };
          reader.readAsDataURL(file);
      }
  };

  const handleStartLesson = async (lesson: Lesson) => {
    setActiveLesson(lesson);
