            </div>

            <div className="flex-1 flex flex-col md:flex-row gap-6">
                <div className="flex-1 flex flex-col">
                    <label className="text-sm font-medium text-gray-500 mb-2">
                        {activeTool === 'Email' ? 'Draft your text below:' : activeTool === 'Behavior' ? 'Describe the interaction:' : 'Upload your photo:'}
                    </label>

                    {activeTool === 'Email' && (
                      <div className="mb-4 flex gap-2 overflow-x-auto pb-2">
                        {['Professional', 'Friendly', 'Assertive', 'Formal', 'Empathetic'].map(t => (
                            <button 
                               key={t}
                               onClick={() => setEmailTone(t)}
                               className={`px-3 py-1.5 rounded-full text-xs font-bold border transition-colors whitespace-nowrap ${emailTone === t ? 'bg-primary-600 text-white border-primary-600' : 'bg-gray-50 dark:bg-gray-700 text-gray-600 dark:text-gray-300 border-transparent hover:border-gray-300'}`}
                            >
                                {t}
                            </button>
                        ))}
                      </div>
                    )}

                    {activeTool === 'Vibe' ? (
                        <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-gray-200 dark:border-gray-700 rounded-xl p-8 bg-gray-50 dark:bg-gray-800">
                             {vibeImage ? (
                                 <img src={vibeImage} alt="Preview" className="max-h-64 rounded-lg shadow-md mb-4" />
                             ) : (
                                 <div className="text-center mb-4">
                                     <Camera className="w-12 h-12 text-gray-300 mx-auto mb-2" />
                                     <p className="text-sm text-gray-500">Click to upload image</p>
                                 </div>
                             )}
                             <input type="file" accept="image/*" onChange={handleImageUpload} className="text-sm text-gray-500" />
                        </div>
                    ) : (
                        <textarea 
                            className="flex-1 p-4 bg-gray-50 dark:bg-gray-800 rounded-xl resize-none focus:outline-none focus:ring-2 focus:ring-primary-500 border border-transparent focus:border-transparent"
                            value={toolInput}
                            onChange={(e) => setToolInput(e.target.value)}
                            placeholder={activeTool === 'Email' ? "e.g., Hi team, I won't make the meeting..." : "He crossed his arms and looked away when I said..."}
                        />
                    )}

                    <button 
                        onClick={handleToolSubmit}
                        disabled={isLoading || (activeTool === 'Vibe' && !vibeImage)}
                        className="mt-4 bg-primary-600 text-white py-3 rounded-xl font-semibold hover:bg-primary-700 transition-colors disabled:opacity-50 shadow-lg shadow-primary-500/30"
                    >
                        {isLoading ? 'Processing...' : (activeTool === 'Email' ? 'Analyze & Refine' : activeTool === 'Behavior' ? 'Analyze Behavior' : 'Analyze Vibe')}
                    </button>
                </div>
                {toolOutput && (
                    <div className="flex-1 bg-gray-50 dark:bg-gray-800/50 p-6 rounded-xl animate-fade-in overflow-y-auto border border-gray-100 dark:border-gray-700">
                         <h3 className="text-sm font-bold text-gray-900 dark:text-white uppercase mb-4 flex items-center gap-2">
                            <Sparkles className="w-4 h-4 text-yellow-500" /> AI Analysis
                         </h3>

                         {activeTool === 'Email' ? (
                            <div className="space-y-6">
                                <div className="bg-yellow-50 dark:bg-yellow-900/10 p-4 rounded-xl border border-yellow-100 dark:border-yellow-900/30">
                                    <h4 className="font-bold text-yellow-700 dark:text-yellow-500 text-xs uppercase mb-2">Critique</h4>
                                    <p className="text-sm text-gray-800 dark:text-gray-200 leading-relaxed">{toolOutput.critique}</p>
                                </div>
                                <div className="bg-green-50 dark:bg-green-900/10 p-4 rounded-xl border border-green-100 dark:border-green-900/30">
                                    <div className="flex justify-between items-center mb-2">
                                        <h4 className="font-bold text-green-700 dark:text-green-500 text-xs uppercase">Polished Version</h4>
                                        <button onClick={() => navigator.clipboard.writeText(toolOutput.rewrite)} className="text-green-600 hover:text-green-700">
                                            <Copy className="w-4 h-4" />
                                        </button>
                                    </div>
                                    <p className="text-sm text-gray-800 dark:text-gray-200 leading-relaxed whitespace-pre-wrap font-medium">{toolOutput.rewrite}</p>
                                </div>
                            </div>
                         ) : activeTool === 'Vibe' ? (
                            <div className="space-y-6">
                                <div className="bg-pink-50 dark:bg-pink-900/10 p-4 rounded-xl border border-pink-100 dark:border-pink-900/30">
                                    <h4 className="font-bold text-pink-700 dark:text-pink-500 text-xs uppercase mb-2">Current Vibe</h4>
                                    <p className="text-lg font-bold text-gray-900 dark:text-white leading-relaxed">"{toolOutput.vibe}"</p>
                                    <p className="text-sm text-gray-700 dark:text-gray-300 mt-2">{toolOutput.impression}</p>
                                </div>
                                <div className="bg-white dark:bg-gray-800 p-4 rounded-xl border border-gray-100 dark:border-gray-700">
                                    <h4 className="font-bold text-gray-900 dark:text-white text-xs uppercase mb-2">Tips to Improve</h4>
                                    <ul className="list-disc list-inside text-sm text-gray-600 dark:text-gray-400 space-y-1">
                                        {(toolOutput.tips || []).map((tip: string, i: number) => (
                                            <li key={i}>{tip}</li>
                                        ))}
                                    </ul>
                                </div>
                            </div>
                         ) : (
                            <p className="text-gray-800 dark:text-gray-200 whitespace-pre-wrap leading-relaxed">{toolOutput}</p>
                         )}
                    </div>
                )}
            </div>
         </div>
       )}
    </div>
  );

  const renderCommunity = () => (
    <div className="h-full flex flex-col animate-fade-in">
       <div className="flex justify-between items-center mb-6">
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Community Hub</h1>
          {!activeCommunityChat && (
              <button 
                onClick={handleFindPartner}
                disabled={isLoading}
                className="px-4 py-2 bg-primary-600 text-white rounded-xl text-sm font-bold hover:bg-primary-700 transition-colors flex items-center gap-2 shadow-lg shadow-primary-500/20"
              >
                  {isLoading ? <span className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></span> : <UserPlus className="w-4 h-4" />}
                  Find Practice Partner
              </button>
          )}
       </div>

       {!activeCommunityChat ? (
         <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {communityUsers.map(user => (
               <div key={user.id} onClick={() => setActiveCommunityChat(user)} className="bg-white dark:bg-dark-card border border-gray-100 dark:border-gray-700 p-6 rounded-2xl flex items-center gap-4 cursor-pointer hover:shadow-lg hover:scale-[1.02] transition-all">
                  <div className="relative">
                     <img src={user.avatar} alt={user.name} className="w-16 h-16 rounded-full object-cover" />
                     <span className={`absolute bottom-0 right-0 w-4 h-4 rounded-full border-2 border-white dark:border-dark-card ${user.status === 'online' ? 'bg-green-500' : user.status === 'busy' ? 'bg-yellow-500' : 'bg-gray-400'}`}></span>
                  </div>
                  <div>
                     <h3 className="font-bold text-gray-900 dark:text-white text-lg">{user.name}</h3>
                     <p className="text-xs text-gray-500">{user.bio}</p>
                     <span className="inline-block mt-2 px-2 py-1 bg-gray-100 dark:bg-gray-800 rounded text-xs font-medium text-gray-600 dark:text-gray-300">
                        {user.status === 'online' ? 'Available to chat' : 'In a session'}
                     </span>
                  </div>
               </div>
            ))}
         </div>
       ) : (
          <div className="flex-1 bg-white dark:bg-dark-card rounded-2xl border border-gray-100 dark:border-gray-700 flex flex-col overflow-hidden">
             <div className="p-4 border-b border-gray-100 dark:border-gray-800 flex justify-between items-center bg-gray-50 dark:bg-gray-800/50">
                <div className="flex items-center gap-3">
                   <img src={activeCommunityChat.avatar} alt={activeCommunityChat.name} className="w-10 h-10 rounded-full" />
                   <div>
                      <h3 className="font-bold text-gray-900 dark:text-white">{activeCommunityChat.name}</h3>
                      <p className="text-xs text-green-500 flex items-center gap-1">
                         <span className="w-1.5 h-1.5 rounded-full bg-green-500"></span> Online
                      </p>
                   </div>
                </div>
                <button onClick={() => setActiveCommunityChat(null)} className="text-sm text-gray-500 hover:text-gray-900 dark:hover:text-white">Back</button>
             </div>
             <div className="flex-1 p-6 flex flex-col items-center justify-center text-center text-gray-500">
                <div className="w-16 h-16 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center mb-4">
                   <Users className="w-8 h-8 text-gray-400" />
                </div>
                <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-2">Start a conversation</h3>
                <p className="max-w-xs mx-auto mb-6">Connect with {activeCommunityChat.name} to practice {activeCommunityChat.bio.toLowerCase()}.</p>
                <button className="px-6 py-2 bg-primary-600 text-white rounded-full font-medium hover:bg-primary-700 transition-colors">
                   Send Invitation
                </button>
             </div>
          </div>
       )}
    </div>
  );

  const renderSettings = () => (
    <div className="max-w-2xl mx-auto animate-fade-in pb-20">
        <h1 className="text-2xl font-bold text-gray-900 dark:text-white mb-6">Profile Settings</h1>

        <div className="bg-white dark:bg-dark-card rounded-2xl border border-gray-100 dark:border-gray-700 p-8 shadow-sm">
            <div className="flex items-center gap-6 mb-8">
                <div className="w-20 h-20 rounded-full bg-primary-100 flex items-center justify-center text-3xl font-bold text-primary-600">
                    {userProfile.name.charAt(0)}
                </div>
                <div>
                    <h2 className="text-xl font-bold text-gray-900 dark:text-white">{userProfile.name}</h2>
                    <p className="text-gray-500">{userProfile.occupation}</p>
                </div>
            </div>

            <div className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Name</label>
                        <input 
                            type="text" 
                            value={userProfile.name}
                            onChange={(e) => setUserProfile({...userProfile, name: e.target.value})}
                            className="w-full p-3 bg-gray-50 dark:bg-gray-800 rounded-xl border-none focus:ring-2 focus:ring-primary-500"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Occupation</label>
                        <input 
                            type="text" 
                            value={userProfile.occupation}
                            onChange={(e) => setUserProfile({...userProfile, occupation: e.target.value})}
                            className="w-full p-3 bg-gray-50 dark:bg-gray-800 rounded-xl border-none focus:ring-2 focus:ring-primary-500"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Age</label>
                        <input 
                            type="text" 
                            value={userProfile.age}
                            onChange={(e) => setUserProfile({...userProfile, age: e.target.value})}
                            className="w-full p-3 bg-gray-50 dark:bg-gray-800 rounded-xl border-none focus:ring-2 focus:ring-primary-500"
                        />
                    </div>
                     <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Gender</label>
                        <select 
                            value={userProfile.gender}
                            onChange={(e) => setUserProfile({...userProfile, gender: e.target.value})}
                            className="w-full p-3 bg-gray-50 dark:bg-gray-800 rounded-xl border-none focus:ring-2 focus:ring-primary-500"
                        >
                            <option>Male</option>
                            <option>Female</option>
                            <option>Non-binary</option>
                            <option>Prefer not to say</option>
                        </select>
                    </div>
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Primary Goal</label>
                    <input 
                        type="text" 
                        value={userProfile.goals}
                        onChange={(e) => setUserProfile({...userProfile, goals: e.target.value})}
                        className="w-full p-3 bg-gray-50 dark:bg-gray-800 rounded-xl border-none focus:ring-2 focus:ring-primary-500"
                    />
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Interests (comma separated)</label>
                    <textarea 
                        value={userProfile.interests}
                        onChange={(e) => setUserProfile({...userProfile, interests: e.target.value})}
                        className="w-full p-3 bg-gray-50 dark:bg-gray-800 rounded-xl border-none focus:ring-2 focus:ring-primary-500 h-24 resize-none"
                    />
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Social Anxiety / Challenge Areas</label>
                    <textarea 
                        value={userProfile.socialAnxieties}
                        onChange={(e) => setUserProfile({...userProfile, socialAnxieties: e.target.value})}
                        className="w-full p-3 bg-gray-50 dark:bg-gray-800 rounded-xl border-none focus:ring-2 focus:ring-primary-500 h-24 resize-none"
                        placeholder="e.g. Public speaking, Small talk with strangers..."
                    />
                </div>

                 <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Learning Style</label>
                    <div className="grid grid-cols-3 gap-3">
                        {['Visual', 'Text-Based', 'Interactive'].map(style => (
                            <button
                                key={style}
                                onClick={() => setUserProfile({...userProfile, learningStyle: style as any})}
                                className={`p-2 rounded-lg text-sm font-medium border ${userProfile.learningStyle === style ? 'bg-primary-50 border-primary-500 text-primary-700' : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-600'}`}
                            >
                                {style}
                            </button>
                        ))}
                    </div>
                </div>
            </div>

            <div className="mt-8 flex justify-end">
                <button 
                  onClick={() => {
                      generateDailyTip(userProfile).then(setDailyTip);
                      alert("Profile Updated!");
                  }}
                  className="px-8 py-3 bg-primary-600 text-white rounded-xl font-bold hover:bg-primary-700 transition-colors shadow-lg shadow-primary-500/30"
                >
                    Save Changes
                </button>
            </div>
        </div>
    </div>
  );

  return (
    <div className={`flex h-screen w-full bg-gray-50 dark:bg-dark-bg transition-colors duration-300 overflow-hidden`}>
      {/* Mobile Nav Overlay */}
      {mobileMenuOpen && (
          <div className="fixed inset-0 bg-black/50 z-50 md:hidden" onClick={() => setMobileMenuOpen(false)} />
      )}

      {/* Sidebar */}
      <nav className={`fixed top-0 left-0 h-full w-64 bg-white dark:bg-dark-card border-r border-gray-200 dark:border-gray-800 z-50 transform transition-transform duration-300 ease-in-out md:translate-x-0 ${mobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} flex flex-col p-6 shadow-2xl md:shadow-none`}>
        <div className="flex items-center gap-3 mb-10">
          <Logo size={48} />
          <div className="flex flex-col font-display">
            <span className="text-2xl font-extrabold text-gray-900 dark:text-white leading-[0.95] tracking-tight">Soci</span>
            <span className="text-2xl font-extrabold text-primary-500 leading-[0.95] tracking-tight">Build</span>
          </div>
        </div>

        <div className="flex flex-col gap-2">
          {[
            { id: View.DASHBOARD, icon: Home, label: 'Dashboard' },
            { id: View.LEARN, icon: GraduationCap, label: 'Learning Portal' },
            { id: View.INTERVIEW, icon: Briefcase, label: 'Interview Prep' },
            { id: View.TOOLS, icon: Zap, label: 'Tools & Practice' },
            { id: View.COMMUNITY, icon: Users, label: 'Community' },
          ].map((item) => (
            <button
              key={item.id}
              onClick={() => { setCurrentView(item.id); setMobileMenuOpen(false); }}
              className={`flex items-center gap-3 p-3 rounded-xl transition-all duration-200 ${
                currentView === item.id
                  ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-600 dark:text-primary-400 font-semibold'
                  : 'text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800'
              }`}
            >
              <item.icon className="w-5 h-5" />
              <span className="text-sm">{item.label}</span>
            </button>
          ))}
        </div>

        <div className="mt-auto">
            <button 
                onClick={() => { setCurrentView(View.SETTINGS); setMobileMenuOpen(false); }}
                className={`flex items-center gap-3 w-full p-3 mb-2 rounded-xl transition-all ${currentView === View.SETTINGS ? 'bg-gray-100 dark:bg-gray-800 text-primary-600' : 'text-gray-500 hover:bg-gray-50 dark:hover:bg-gray-800'}`}
            >
               <Settings className="w-5 h-5" />
               <span className="text-sm">Settings</span>
            </button>

            {/* User Mini Profile */}
            <div className="flex items-center gap-3 p-3 mb-4 bg-gray-50 dark:bg-gray-800 rounded-xl cursor-pointer" onClick={() => setCurrentView(View.SETTINGS)}>
                <div className="w-10 h-10 rounded-full bg-primary-100 flex items-center justify-center text-primary-600 font-bold">
                  {userProfile.name.charAt(0)}
                </div>
                <div className="flex-1 overflow-hidden">
                    <p className="text-sm font-bold text-gray-900 dark:text-white truncate">{userProfile.name}</p>
                    <p className="text-xs text-gray-500 truncate">{userProfile.occupation}</p>
                </div>
            </div>

            <button 
                onClick={toggleTheme}
                className="flex items-center gap-3 w-full p-3 text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-xl transition-all"
            >
                {darkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
                <span className="text-sm font-medium">{darkMode ? 'Light Mode' : 'Dark Mode'}</span>
            </button>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 overflow-hidden relative flex flex-col md:ml-64">
        {/* Mobile Header */}
        <div className="md:hidden flex justify-between items-center p-4 bg-white/80 dark:bg-dark-card/80 backdrop-blur-md z-40 border-b border-gray-100 dark:border-gray-800">
           <button onClick={() => setMobileMenuOpen(true)} className="p-2"><Menu className="w-6 h-6 text-gray-900 dark:text-white" /></button>
           <div className="flex items-center gap-2">
             <Logo size={32} />
             <div className="flex flex-col font-display">
                <span className="text-lg font-extrabold text-gray-900 dark:text-white leading-[0.95] tracking-tight">Soci</span>
                <span className="text-lg font-extrabold text-primary-500 leading-[0.95] tracking-tight">Build</span>
             </div>
           </div>
           <div className="w-10"></div> 
        </div>

        <div className="flex-1 overflow-y-auto p-4 md:p-8">
           <div className="max-w-6xl mx-auto h-full">
                {currentView === View.DASHBOARD && renderDashboard()}
                {currentView === View.LEARN && renderLearn()}
                {currentView === View.INTERVIEW && renderInterviewPrep()}
                {currentView === View.TOOLS && renderTools()}
                {currentView === View.COMMUNITY && renderCommunity()}
                {currentView === View.SETTINGS && renderSettings()}

                {currentView === View.CHAT && (
                    <div className="flex flex-col h-[calc(100vh-140px)] md:h-[calc(100vh-80px)]">
                      <div className="flex items-center gap-4 mb-4 pb-4 border-b border-gray-100 dark:border-gray-800">
                        <button onClick={() => setCurrentView(View.DASHBOARD)} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-full transition-colors">
                          <X className="w-5 h-5 text-gray-600 dark:text-gray-300" />
                        </button>
                        <div className="flex-1">
                          <h2 className="font-bold text-gray-900 dark:text-white">{activeScenario?.title}</h2>
                          <p className="text-xs text-primary-500 flex items-center gap-1">Speaking with: {activeScenario?.aiPersona}</p>
                        </div>
                        {lastAnalysis && (
                            <ConfidenceMeter score={lastAnalysis.confidenceScore} />
                        )}
                      </div>
                      <div className="flex-1 overflow-y-auto space-y-4 pr-2 mb-4 scrollbar-hide">
                        {messages.map((msg) => (
                          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                            <div className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm ${msg.role === 'user' ? 'bg-primary-600 text-white rounded-br-none' : 'bg-white dark:bg-gray-800 text-gray-800 dark:text-gray-200 rounded-bl-none border border-gray-100 dark:border-gray-700'}`}>
                              {msg.text}
                            </div>
                          </div>
                        ))}
                        {isLoading && (
                            <div className="flex justify-start">
                                <div className="bg-white dark:bg-gray-800 p-4 rounded-2xl rounded-bl-none border border-gray-100 dark:border-gray-700 flex gap-2">
                                <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></span>
                                <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-100"></span>
                                <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-200"></span>
                                </div>
                            </div>
                        )}
                        <div ref={chatEndRef} />
                      </div>
                      {lastAnalysis && !isLoading && (
                        <div className="absolute bottom-20 left-4 right-4 md:left-auto md:right-10 md:w-80 bg-white/95 dark:bg-gray-800/95 backdrop-blur shadow-2xl border border-primary-100 dark:border-gray-700 p-4 rounded-xl text-xs animate-slide-up z-30">
                           <div className="flex justify-between items-start mb-2">
                               <h4 className="font-bold text-primary-600 uppercase tracking-wider">Coach Insight</h4>
                           </div>
                           <p className="text-gray-700 dark:text-gray-300 mb-1">{lastAnalysis.feedback}</p>
                           {lastAnalysis.betterAlternative && <p className="text-gray-500 italic border-l-2 border-primary-200 pl-2 mt-2">Try: "{lastAnalysis.betterAlternative}"</p>}
                        </div>
                      )}
                      <div className="relative">
                        <input
                          type="text"
                          value={inputText}
                          onChange={(e) => setInputText(e.target.value)}
                          onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                          placeholder="Type your response..."
                          disabled={isLoading}
                          className="w-full bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 text-gray-900 dark:text-white rounded-xl pl-4 pr-14 py-4 focus:outline-none focus:ring-2 focus:ring-primary-500 transition-all shadow-sm"
                        />
                        <button onClick={handleSendMessage} disabled={isLoading || !inputText.trim()} className="absolute right-2 top-2 p-2 bg-primary-600 hover:bg-primary-700 text-white rounded-lg transition-colors">
                          <Send className="w-5 h-5" />
                        </button>
                      </div>
                    </div>
                )}
           </div>
        </div>
      </main>
    </div>
  );
}

export default App;
